import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import { useParams, useNavigate } from 'react-router-dom';
import { Room, RoomEvent, Track } from 'livekit-client';

const SimpleLiveKit: React.FC = () => {
  const { interviewId, agentId } = useParams<{ interviewId?: string; agentId?: string }>();
  const { state: authState } = useAuth();
  const navigate = useNavigate();

  const [messages, setMessages] = useState<string[]>([]);
  const [isConnected, setIsConnected] = useState(false);
  const [sessionStarted, setSessionStarted] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [micEnabled, setMicEnabled] = useState(false);
  const [feedback, setFeedback] = useState<any>(null);

  const roomRef = useRef<Room | null>(null);
  const websocketRef = useRef<WebSocket | null>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const remoteAudioRef = useRef<HTMLAudioElement>(null);

  useEffect(() => {
    if (interviewId || agentId) {
      initializeSession();
    }
    return () => cleanup();
  }, [interviewId, agentId]);

  const initializeSession = async () => {
    const sessionId = interviewId || agentId;

    // Connect to WebSocket
    const wsUrl = `ws://localhost:8000/ws/${sessionId}`;
    websocketRef.current = new WebSocket(wsUrl);

    websocketRef.current.onopen = () => {
      console.log('WebSocket connected');
      setIsConnected(true);

      websocketRef.current?.send(JSON.stringify({
        type: 'join_session',
        participant_id: authState.user?.id,
        participant_name: `${authState.user?.first_name} ${authState.user?.last_name}`,
        role: 'student',
        session_type: agentId ? 'practice' : 'interview'
      }));
    };

    websocketRef.current.onmessage = (event) => {
      const data = JSON.parse(event.data);
      handleWebSocketMessage(data);
    };
  };

  const handleWebSocketMessage = (data: any) => {
    switch (data.type) {
      case 'session_ready':
        console.log('Session ready:', data);
        setSessionStarted(true);
        if (data.livekit_info) {
          connectToLiveKit(data.livekit_info);
        }
        break;
      case 'ai_response':
        setMessages(prev => [...prev, `AI: ${data.message}`]);
        break;
      case 'ai_audio':
        console.log('AI audio received');
        playAudioFromBase64(data.audio_data);
        break;
      case 'interview_feedback':
        console.log('Interview feedback:', data.feedback);
        setFeedback(data.feedback);
        break;
    }
  };

  const connectToLiveKit = async (livekitInfo: any) => {
    try {
      console.log('Connecting to LiveKit...');

      const room = new Room({
        adaptiveStream: true,
        dynacast: true,
      });

      roomRef.current = room;

      // Set up event listeners
      room.on(RoomEvent.ParticipantConnected, (participant: any) => {
        console.log('Participant connected:', participant.identity);
      });

      room.on(RoomEvent.ParticipantDisconnected, (participant: any) => {
        console.log('Participant disconnected:', participant.identity);
      });

      room.on(RoomEvent.TrackSubscribed, (track: any, publication: any, participant: any) => {
        console.log('Track subscribed:', track.kind, 'from:', participant.identity);

        if (track.kind === Track.Kind.Audio) {
          const audioElement = remoteAudioRef.current;
          if (audioElement) {
            track.attach(audioElement);
            console.log('Remote audio track attached');
          }
        }
      });

      // Connect to room
      await room.connect(livekitInfo.url, livekitInfo.token, {
        autoSubscribe: true,
      });

      console.log('Connected to LiveKit room');

      // Enable microphone
      await room.localParticipant.setMicrophoneEnabled(true);
      setMicEnabled(true);

      // Start recording
      startRecording();

      console.log('LiveKit connected successfully');

    } catch (error) {
      console.error('LiveKit connection failed:', error);
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        audio: {
          echoCancellation: true,
          noiseSuppression: true,
          autoGainControl: true,
        } 
      });

      const mediaRecorder = new MediaRecorder(stream, {
        mimeType: 'audio/webm;codecs=opus'
      });

      mediaRecorderRef.current = mediaRecorder;

      mediaRecorder.ondataavailable = async (event) => {
        if (event.data.size > 0) {
          const arrayBuffer = await event.data.arrayBuffer();
          const uint8Array = new Uint8Array(arrayBuffer);
          const base64Audio = btoa(String.fromCharCode.apply(null, Array.from(uint8Array)));

          websocketRef.current?.send(JSON.stringify({
            type: 'audio_data',
            audio_data: base64Audio,
            interview_id: interviewId || agentId
          }));
        }
      };

      mediaRecorder.start(2000);
      setIsRecording(true);

    } catch (error) {
      console.error('Recording failed:', error);
    }
  };

  const playAudioFromBase64 = (base64Audio: string) => {
    try {
      const audioData = atob(base64Audio);
      const audioArray = new Uint8Array(audioData.length);
      for (let i = 0; i < audioData.length; i++) {
        audioArray[i] = audioData.charCodeAt(i);
      }

      const audioBlob = new Blob([audioArray], { type: 'audio/wav' });
      const audioUrl = URL.createObjectURL(audioBlob);

      const audio = new Audio(audioUrl);
      audio.play().catch(error => {
        console.error('Error playing audio:', error);
      });

    } catch (error) {
      console.error('Error playing audio from base64:', error);
    }
  };

  const toggleMicrophone = async () => {
    if (!roomRef.current) return;

    try {
      if (micEnabled) {
        await roomRef.current.localParticipant.setMicrophoneEnabled(false);
        setMicEnabled(false);
      } else {
        await roomRef.current.localParticipant.setMicrophoneEnabled(true);
        setMicEnabled(true);
      }
    } catch (error) {
      console.error('Error toggling microphone:', error);
    }
  };

  const sendTextMessage = () => {
    const message = prompt('Enter your message:');
    if (message && websocketRef.current) {
      websocketRef.current.send(JSON.stringify({
        type: 'text_message',
        message: message
      }));
    }
  };

  const cleanup = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
    }
    if (roomRef.current) {
      roomRef.current.disconnect();
    }
    if (websocketRef.current) {
      websocketRef.current.close();
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      <div className="max-w-6xl mx-auto">
        {/* Header */}
        <div className="bg-white rounded-lg shadow-sm p-6 mb-6">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-bold text-gray-900">
                LiveKit Voice Interview
              </h1>
              <p className="text-gray-600">
                Real-time voice communication with AI interviewer
              </p>
            </div>
            <div className="flex items-center space-x-4">
              <div className={`flex items-center space-x-2 ${isConnected ? 'text-green-600' : 'text-red-600'}`}>
                <div className={`w-3 h-3 rounded-full ${isConnected ? 'bg-green-500' : 'bg-red-500'}`}></div>
                <span className="font-medium">{isConnected ? 'Connected' : 'Disconnected'}</span>
              </div>
              {isRecording && (
                <div className="flex items-center space-x-2 text-red-600">
                  <div className="w-3 h-3 rounded-full bg-red-500 animate-pulse"></div>
                  <span className="font-medium">Recording</span>
                </div>
              )}
              {sessionStarted && (
                <div className="flex items-center space-x-2 text-blue-600">
                  <div className="w-3 h-3 rounded-full bg-blue-500 animate-pulse"></div>
                  <span className="font-medium">Session Active</span>
                </div>
              )}
              <div className={`flex items-center space-x-2 ${micEnabled ? 'text-green-600' : 'text-red-600'}`}>
                <div className={`w-3 h-3 rounded-full ${micEnabled ? 'bg-green-500' : 'bg-red-500'}`}></div>
                <span className="font-medium">{micEnabled ? 'Mic On' : 'Mic Off'}</span>
              </div>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* LiveKit Audio Controls */}
          <div className="bg-white rounded-lg shadow-sm p-6">
            <h2 className="text-lg font-semibold mb-4">Audio Controls</h2>

            <div className="space-y-4">
              <div className="flex items-center space-x-4">
                <button
                  onClick={toggleMicrophone}
                  className={`px-4 py-2 rounded-lg font-medium ${
                    micEnabled 
                      ? 'bg-red-500 text-white hover:bg-red-600' 
                      : 'bg-green-500 text-white hover:bg-green-600'
                  }`}
                >
                  {micEnabled ? 'Disable Mic' : 'Enable Mic'}
                </button>
              </div>

              <div className="flex items-center space-x-4">
                <button
                  onClick={sendTextMessage}
                  className="bg-blue-500 text-white px-4 py-2 rounded-lg hover:bg-blue-600"
                >
                  Send Text Message
                </button>
                <button
                  onClick={() => navigate('/dashboard')}
                  className="bg-red-500 text-white px-4 py-2 rounded-lg hover:bg-red-600"
                >
                  End Session
                </button>
              </div>

              <div className="text-sm text-gray-600 space-y-1">
                <p>Status: {isRecording ? 'Recording audio' : 'Not recording'}</p>
                <p>LiveKit: {roomRef.current ? 'Connected' : 'Disconnected'}</p>
                <p>WebSocket: {isConnected ? 'Connected' : 'Disconnected'}</p>
              </div>
            </div>

            {/* Audio elements */}
            <audio ref={remoteAudioRef} autoPlay style={{ display: 'none' }} />
          </div>

          {/* Messages */}
          <div className="bg-white rounded-lg shadow-sm p-6 lg:col-span-2">
            <h2 className="text-lg font-semibold mb-4">Conversation</h2>

            <div className="h-96 overflow-y-auto mb-4 border rounded-lg p-4">
              {messages.length === 0 ? (
                <div className="text-center text-gray-500">
                  <p>Waiting for AI interviewer...</p>
                </div>
              ) : (
                <div className="space-y-2">
                  {messages.map((msg, index) => (
                    <div key={index} className="mb-2 p-2 bg-gray-100 rounded">
                      {msg}
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Feedback */}
        {feedback && (
          <div className="bg-white rounded-lg shadow-sm p-6 mt-6">
            <h2 className="text-lg font-semibold mb-4">Interview Feedback</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="bg-blue-50 p-4 rounded-lg">
                <h3 className="font-semibold">Overall Score</h3>
                <p className="text-2xl font-bold text-blue-600">{feedback.overall_score}/10</p>
              </div>
              <div className="bg-green-50 p-4 rounded-lg">
                <h3 className="font-semibold">Strengths</h3>
                <ul className="text-sm">
                  {feedback.strengths?.map((strength: string, index: number) => (
                    <li key={index}>• {strength}</li>
                  ))}
                </ul>
              </div>
              <div className="bg-yellow-50 p-4 rounded-lg">
                <h3 className="font-semibold">Improvements</h3>
                <ul className="text-sm">
                  {feedback.improvements?.map((improvement: string, index: number) => (
                    <li key={index}>• {improvement}</li>
                  ))}
                </ul>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default SimpleLiveKit;
